const grpc = require('@grpc/grpc-js');
const metadata = new grpc.Metadata();

// Accept custom headers from HTTP requests and inject them into gRPC metadata using metadata.add()
function forwardHeaders(headers) {
  for (let header of Object.keys(headers)) {
    if (header === 'user-agent' || header === 'x-forwarded-for') {
      // Pass headers like user-agent and x-forwarded-for directly to backend services
      metadata.add(header, headers[header]);
    } else {
      // Add custom headers to gRPC metadata
      metadata.add('custom-' + header, headers[header]);
    }
  }
}

// Create a gRPC client using the forwardHeaders function
const client = new grpc.Client(forwardHeaders);

// Use the client to make gRPC requests with the custom headers injected into the metadata
client.makeRequest('myService', 'myMethod', {}, metadata, (err, response) => {
  if (err) {
    console.error(err);
  } else {
    console.log(response);
  }
});